from qiskit import QuantumCircuit
from qiskit.transpiler import CouplingMap
from qiskit.providers.fake_provider import GenericBackendV2

be = GenericBackendV2(5, coupling_map=CouplingMap.from_line(5), seed=3)
basis = set(be.operation_names)
edges = set()
for a, b in be.coupling_map.get_edges():
    edges.add((a, b)); edges.add((b, a))

def is_isa(qc):
    for ins in qc.data:
        name = ins.operation.name
        if name in ("barrier", "measure"):
            continue
        if name not in basis:
            return False, f"{name} not in basis {sorted(basis)}"
        if ins.operation.num_qubits == 2:
            q = tuple(qc.find_bit(x).index for x in ins.qubits)
            if q not in edges:
                return False, f"{name} on non-adjacent {q}"
    return True, "only basis gates on adjacent qubits"

def cA():
    qc = QuantumCircuit(5); qc.rz(0.5, 0); qc.sx(0); qc.cx(0, 1); return qc
def cB():
    qc = QuantumCircuit(5); qc.h(0); return qc
def cC():
    qc = QuantumCircuit(5); qc.cx(0, 4); return qc
def cD():
    qc = QuantumCircuit(5); qc.ccx(0, 1, 2); return qc

res = {"A": is_isa(cA()), "B": is_isa(cB()), "C": is_isa(cC()), "D": is_isa(cD())}
claims = {k: res[k][0] for k in res}
evidence = {k: f"is_isa -> {res[k][0]} ({res[k][1]})" for k in res}
proven = [k for k, v in claims.items() if v]
emit_verdict({"answer": proven, "evidence": evidence, "observed": {k: res[k][0] for k in res}})
